INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (1,'Integridad','Rectitud, coherencia con los valores propios de la empresa y el código de ética, conducirse con los ideales, pensamientos y políticas establecidos.',1,0,3,'2020-07-22 23:55:07','2020-07-22 23:55:07',NULL),
	 (2,'Trabajo en equipo','Participar activamente con los compañeros de trabajo para llegar al objetivo en común, donde se suman las capacidades individuales para producir mejores resultados.',1,0,3,'2020-08-04 16:21:37','2020-08-04 16:21:37',NULL),
	 (3,'Actitud de servicio','Contar con la disposición permanente de apoyar al cliente interno y/o externo de forma entusiasta con sentido de colaboración.',1,0,3,'2020-08-04 16:22:06','2021-08-25 20:27:19',NULL),
	 (4,'Perseverancia','Capacidad de lograr el objetivo más allá de los obstáculos, aprende de los errores y los convierte en experiencias para así fortalecer sus habilidades y competencias',1,0,3,'2020-08-04 16:23:22','2021-08-25 20:27:23',NULL),
	 (5,'Liderazgo','Conjunto de habilidades que reúne una persona que marca la diferencia en el equipo de trabajo, es guía y formador de quienes lo rodean, toma las mejores decisiones para lograr los objetivos de la empresa sin dejar de lado al equipo.',1,0,3,'2020-08-04 16:23:53','2021-08-25 20:27:08',NULL),
	 (6,'Excelencia','Esfuerzo continuo en cumplir con las especificaciones, parámetros y tiempos; superando incluso las expectativas del cliente interno o externo.',1,0,3,'2020-08-04 16:24:58','2021-08-25 20:27:03',NULL),
	 (7,'Iniciativa','Buscar soluciones, el punto de partida para encontrar el "como sí" lograr el objetivo en mente, ser propositivo, creativo y poner en marcha las ideas proyectadas para alcanzar el éxito.',1,0,3,'2020-08-04 16:25:35','2021-08-25 20:26:58',NULL),
	 (8,'Adaptación al cambio','Capacidad de adaptación a los cambios organizacionales, ser consciente de que el cambio conlleva oportunidades de mejora. Estar dispuesto y con la mejor actitud para aportar a la organización en transiciones de cambio.',1,0,3,'2020-08-04 16:26:11','2021-08-25 20:26:54',NULL),
	 (9,'Pasión','Interés, emoción y entusiasmo por ser parte de los proyectos organizacionales, contagiar el espíritu colaborativo hacia los demás miembros del equipo. Querer lo que se hace y luchar día a día por mejorar lo que se ofrece.',1,0,3,'2020-08-04 16:26:36','2021-08-25 20:26:50',NULL),
	 (10,'Compromiso','Identificarse con las metas de la empresa, hacerlas propias y dar todo de sí para la contribución del logro de las mismas. Tener la camiseta puesta, ser empático y entender donde se encuentra la organización y qué se necesita para lograr los resultados esperados.',1,0,3,'2020-08-04 16:27:11','2020-08-04 16:27:11',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (11,'Retroalimentación','Saber dar y/o recibir críticas constructivas por parte de los compañeros de equipo, con el objetivo de aportar al desarrollo y mejora de los mismos, estas deben estar basadas en una situación, comportamiento e impacto.',1,0,3,'2020-08-04 16:27:48','2021-08-25 20:26:42',NULL),
	 (12,'Responsabilidad social','Aportar ideas o estrategias para el desarrollo y competitividad con base a beneficios para la sociedad o medio ambiente.',1,0,3,'2020-08-04 16:28:21','2021-08-25 20:26:38',NULL),
	 (13,'Confianza','Asegurar la confiabilidad del servicio, fortalecer la relación con el cliente generando dinámicas fluidas y eficaces mejorando así la productividad y proyectando credibilidad, congruencia entre lo que se dice y se hace.',1,0,3,'2020-08-04 16:28:41','2021-08-25 20:26:05',NULL),
	 (14,'Mejor Servicio','Esa persona que siempre está dando su máximo esfuerzo para brindarle el mejor servicio a los clientes.',1,1,3,'2020-09-30 00:57:52','2021-08-25 20:46:26',NULL),
	 (15,'Ética','La serie de valores y principios por los cuales se rige una persona dentro de la empresa a la hora de llevar a cabo sus acciones y actividades.',1,1,3,'2021-12-22 22:46:01','2021-12-22 22:48:18',NULL),
	 (16,'Innovación','La aplicación de nuevas ideas, conceptos, servicios y prácticas, con la intención de aumentar la productividad y competitividad de la empresa.',1,1,3,'2021-12-22 22:46:35','2021-12-22 22:48:44',NULL),
	 (17,'Calidad','Siempre tener presente las expectativas de los clientes, para poder satisfacerlas al máximo e incluso superarlas.',1,1,3,'2021-12-23 00:03:54','2021-12-23 00:03:54',NULL),
	 (18,'Responsabilidad','Cumplir con las obligaciones dentro de la empresa. Asumir las consecuencias de las acciones.',1,1,3,'2021-12-23 00:05:13','2021-12-23 00:05:13',NULL),
	 (19,'Creer en nuestra capacidad','Parte de la base que todos tenemos grandes capacidades, las valora y reconoce en las personas con las que interactúa e incluso las desarrolla aún más. Al interactuar con otras personas promueve un espacio respetuoso y un ambiente positivo.',0,1,3,'2022-01-06 22:34:46','2022-06-15 17:13:38',NULL),
	 (20,'Seguridad es nuestra prioridad','Contribuye a la creación de una cultura de seguridad, trabajando en forma segura, siguiendo las normas existentes y usando su equipo de protección personal.',0,1,3,'2022-01-06 22:36:09','2022-06-15 17:13:34',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (21,'Trabajando arduo y mejora continua','Promueve mejoras constantes en los procesos de su área llevando a cabo sus actividades correctamente y de acuerdo con los estándares de la empresa.',0,1,3,'2022-01-06 22:37:19','2022-06-15 17:13:30',NULL),
	 (22,'Exceder las expectativas del cliente','No importa si el cliente es interno o externo, se anticipa y resuelve sus necesidades, busca de manera proactiva soluciones de satisfacción y la lealtad del cliente.',0,1,3,'2022-01-06 22:38:50','2022-06-15 17:13:26',NULL),
	 (23,'Desarrollo personal','Comparte su conocimiento y desarrolla a sus compañeros, además de que es ejemplo de autodesarrollo.',0,1,3,'2022-01-06 22:39:47','2022-06-15 17:13:23',NULL),
	 (24,'Honestidad e integridad','Mantiene una comunicación abierta y sincera; promueve debates constructivos, hace lo correcto, se apega a la normatividad y cumple lo que promete.',0,1,3,'2022-01-06 22:40:52','2022-06-15 17:13:20',NULL),
	 (25,'Hacerlo mejor','Es quien destaca por sus resultados o desempeño extraordinario, es referente para el equipo en calidad, productividad, eficiencia, servicio al cliente, liderazgo, etcétera',0,1,3,'2022-01-06 22:41:48','2022-06-15 17:13:16',NULL),
	 (26,'Celebrar el éxito','Valora el esfuerzo de sus compañeros, les reconoce y motiva abiertamente cuando logran los resultados esperados.',0,1,3,'2022-01-06 22:42:46','2022-06-15 17:12:52',NULL),
	 (27,'Respeto','Escucho, acepto y soy tolerante a las opiniones y puntos de vista de los demás.',1,1,3,'2022-02-24 01:11:10','2022-10-06 22:07:57',NULL),
	 (28,'Trabajo en Equipo','Comparto, coopero y participo de forma activa, propongo ideas y alternativas para el logro de objetivos y retos.',1,1,3,'2022-02-24 01:11:57','2022-10-06 22:08:12',NULL),
	 (29,'Responsabilidad','Cumplo con las obligaciones de mis labores, cuido de las instalaciones, medio ambiente y sigo los lineamientos de seguridad para el cuidado de mi persona.',1,1,3,'2022-02-24 01:12:27','2022-10-06 22:08:38',NULL),
	 (30,'Honestidad','Soy congruente en lo que digo y hago, me muestro transparente, cumplo mi palabra y cuido la dignidad de mis compañeros.',1,1,3,'2022-02-24 01:13:23','2022-10-06 22:10:45',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (31,'Compromiso','Me esfuerzo en cumplir con mis deberes buscando mejorar cada día, sin perder el tiempo y sin buscar excusas.',1,1,3,'2022-02-24 01:14:04','2022-10-06 22:11:23',NULL),
	 (32,'Integridad','Hago lo correcto sin esperar que alguien me lo pida, cuidando con mis acciones el bienestar de mis compañeros y familia.',1,1,3,'2022-02-24 01:14:36','2022-10-06 22:12:11',NULL),
	 (33,'Pasión','Realizo mis labores con entusiasmo y entrega para lograr mis objetivos personales y los objetivos de la empresa.',1,1,3,'2022-02-24 01:15:07','2022-10-06 22:12:34',NULL),
	 (34,'Bienvenida','Envía un mensaje de bienvenida a personal de nuevo ingreso y mantente en contacto con tus compañeros.',0,1,3,'2022-02-24 01:15:34','2022-10-06 22:13:06',NULL),
	 (35,'Somos atentos','Nuestro enfoque permanente está puesto en las personas, su diversidad y sus ideas. Fomentamos una cultura de pensamiento libre y de resolución de problemas. Somos parte de un bien mayor, celebremos juntos el éxito y hagamos que el mundo sea un poco mejor.',1,1,3,'2022-06-15 17:27:05','2022-06-15 17:27:05',NULL),
	 (36,'Somos comprometidos','Somos miembros de un equipo que confía el uno en el otro para lograr lo mejor. Cada vez que realizamos una tarea, tengamos presente que un cliente o un compañero cuenta con nuestro trabajo, por lo que debemos dar lo mejor de nosotros mismos buscando siempre la mejora continua.',1,1,3,'2022-06-15 17:27:29','2022-06-15 17:27:29',NULL),
	 (37,'Somos curiosos','La innovación surge del afán de hacer las cosas mejor. Tener la mente abierta significa que daremos a las nuevas ideas su justa medida antes de emitir un juicio.',1,1,3,'2022-06-15 17:28:10','2022-06-15 17:28:10',NULL),
	 (38,'Somos honestos','La verdad precede al conocimiento No puede haber ciencia basada en una falsedad. Sea honesto en todo lo que sabe, y también en lo que no sabe. Hable con simpleza e integridad para que las personas puedan valorarlo.',1,1,3,'2022-06-15 17:28:39','2022-06-15 17:28:39',NULL),
	 (39,'Somos resilientes','Nada que valga la pena es fácil. Es precisamente nuestra capacidad de superar obstáculos y la confianza en nosotros mismos lo que le aporta valor a usted como a la tarea que debe realizar.',1,1,3,'2022-06-15 17:29:09','2022-06-15 17:29:09',NULL),
	 (40,'Somos seguros','La gestión de los riesgos es más que una política, es parte de nuestro ADN. Está incorporada en nuestro modelo operativo y es una prioridad. Es simplemente el modo en lo que hacemos negocios.',1,1,3,'2022-06-15 17:29:32','2022-06-15 17:29:32',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (41,'Crack','El colaborador que la rompe todo el tiempo por su talento y capacidad.',0,1,3,'2022-11-09 23:22:43','2023-01-04 20:16:13',NULL),
	 (42,'El Mejor Jugador','Colaborador destacado por su gran actuación en una actividad.',0,1,3,'2022-11-09 23:24:22','2023-01-04 20:15:35',NULL),
	 (43,'El Capi','Tiene la camiseta bien puesta con su ejemplo y gran liderazgo',0,1,3,'2022-11-09 23:24:53','2023-01-04 20:14:29',NULL),
	 (44,'El Balón de Oro','Uno de los máximos reconocimientos para el colaborador que se destaca en cada labor o actividad, mostrando liderazgo, empatía y trabajo en equipo.',0,1,3,'2022-11-09 23:25:31','2023-01-04 20:14:13',NULL),
	 (45,'La bujía del Equipo','Mantiene a flote el equipo por medio de su empatía y manteniendo la chispa de todo el equipo.',0,1,3,'2022-11-09 23:26:07','2023-01-04 20:13:50',NULL),
	 (46,'Resiliencia','Desarrollamos y fortalecemos nuestra capacidad de reacción y adaptación.',1,1,3,'2023-03-14 18:11:42','2023-07-18 12:49:21',NULL),
	 (47,'Honestidad','En todas las acciones emprendidas por nuestra empresa, accionistas y colaboradores.',1,1,3,'2023-03-14 18:17:13','2023-03-14 18:17:13',NULL),
	 (48,'Respeto','Reconoce, acepta y valora a tus compañeros, comunidad, instituciones y clientes.',1,1,3,'2023-03-14 18:20:32','2023-03-14 18:20:32',NULL),
	 (49,'Compromiso','Involucramiento y pasión en todas nuestras actividades.',1,1,3,'2023-03-14 18:21:52','2023-03-14 18:21:52',NULL),
	 (50,'Trabajo en Equipo','Participar activamente con los compañeros de trabajo para llegar al objetivo en común, donde se suman las capacidades individuales para producir mejores resultados.',1,1,3,'2023-03-14 18:25:49','2023-03-14 19:50:57',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (51,'Empleado del Mes','Reconoce y nomina a ese compañero o compañera que tiene la camiseta bien puesta y demuestra el compromiso con el servicio, con sus compañeros de trabajo y que vive los valores de la empresa.',1,1,3,'2023-04-24 14:53:57','2023-04-24 14:53:57',NULL),
	 (52,'Global MICEC','MAGIA: Crear momentos inolvidables.
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (61,'4-) Amor','Sentimos emoción por nuestro trabajo y lo demostramos.',1,1,3,'2023-09-22 12:02:21','2023-09-25 11:15:13',NULL),
	 (62,'5-) Respeto','Nos dirigimos a los compañeros con ética y moral, una persona cuando es respetuosa acepta y comprende las maneras de pensar y actuar distintas a las de ella.',1,1,3,'2023-09-22 12:02:52','2023-09-25 11:15:26',NULL),
	 (63,'6-) Mucha Galleta','¡Gracias por vivir nuestros valores y ser un ejemplo para todo el equipo!',1,1,3,'2023-09-22 12:03:31','2023-09-25 11:15:40',NULL),
	 (64,'Pasión','Realiza sus actividades siempre con buen ánimo. Se asegura de cumplir con las especificaciones del cliente de manera correcta. Ofrece su ayuda a su equipo para cumplir con las metas.',1,1,3,'2023-10-30 16:58:58','2023-10-30 16:58:58',NULL),
	 (65,'Innovación','Propone nuevas formas de realizar las actividades. Busca mejorar los procesos ya existentes. Está dispuesto a capacitar a sus nuevos compañeros en los procesos internos.',1,1,3,'2023-10-30 16:59:33','2023-10-30 16:59:33',NULL),
	 (66,'Enfoque','Llega a sus metas de manera constante. Termina las tareas asignadas en tiempo y forma.
