	 (81,'Honestidad','Como base de actuación y norma de conducta (legalidad).',1,1,3,'2023-11-28 18:08:48','2023-11-28 18:08:48',NULL),
	 (82,'Profesionalismo','Como garantía de nuestro trabajo.',1,1,3,'2023-12-20 16:48:31','2023-12-20 16:48:31',NULL),
	 (83,'Eficiencia','Como garantía de nuestro trabajo.',1,1,3,'2023-12-20 16:49:09','2023-12-20 16:49:09',NULL),
	 (84,'Alegría de Vivir','Creamos un lugar donde disfrutamos y crecemos como personas.',0,1,3,'2023-12-26 09:34:24','2024-01-09 12:49:13',NULL),
	 (85,'Trayectoria y compromiso','Dedicación, perseverancia y participación activa en las tareas diarias y en la misión y visión de la organización.',1,1,3,'2024-02-15 17:18:57','2024-02-15 17:18:57',NULL),
	 (86,'Higiene de Alimentos','Cumplimiento de la Norma 251, SSA1 2009 de manejo higiénico normativos.',1,1,3,'2024-02-15 17:19:34','2024-02-15 17:19:34',NULL),
	 (87,'Puntualidad y asistencia','Llegar, realizar y/o completar sus tareas, actividades o encuentros en el momento acordado, sin retrasos ni demoras.',1,1,1,'2024-02-15 17:20:07','2024-02-15 17:20:07',NULL),
	 (88,'Trabajo en equipo','Capacidad de comunicarse efectivamente, coordinar esfuerzos y colaborar de manera respetuosa y asertiva para lograr los objetivos diarios.',1,1,3,'2024-02-15 17:20:54','2024-02-15 17:20:54',NULL),
	 (89,'Servicio al cliente','Lleva a cabo las acciones y los procesos para satisfacer las necesidades, inquietudes y demandas de los clientes de manera efectiva y satisfactoria.',1,1,3,'2024-02-15 17:21:49','2024-02-15 17:21:49',NULL),
	 (90,'Liderazgo','Habilidad de inspirar, influir y capacitar a otros para que trabajen de manera colaborativa y efectiva hacia un objetivo común.',1,1,3,'2024-02-15 17:22:17','2024-02-15 17:22:17',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (91,'Bold ideas/Creatividad','Se refiere a la capacidad de generar ideas originales y soluciones innovadoras para abordar problemas, desafíos o proyectos. La creatividad no se limita a las artes o el diseño, sino que es una habilidad valiosa en una amplia variedad de campos y situaciones.',1,1,3,'2024-03-12 15:47:14','2024-03-12 15:48:08',NULL),
	 (92,'Excellency/Excelencia','Se refiere a la búsqueda constante de altos estándares de calidad, rendimiento y logros en todas las actividades y responsabilidades que una persona emprende. La excelencia implica un compromiso continuo con la mejora y la entrega de resultados sobresalientes siempre excediendo las expectativas de los clientes de MM&A Latin.',1,1,3,'2024-03-12 15:47:58','2024-03-12 15:47:58',NULL),
	 (93,'Accountability/ Responsabilidad','Se refiere a la responsabilidad personal y profesional de asumir la propiedad de las acciones, decisiones y resultados. Esta competencia es esencial para mantener la transparencia, la confianza y la responsabilidad en todas las interacciones y tareas.',1,1,3,'2024-03-12 15:48:50','2024-03-12 15:48:50',NULL),
	 (94,'Team Players/ Trabajo en equipo','Se refiere a la capacidad de trabajar eficazmente en un equipo y colaborar de manera productiva con otros miembros del grupo',1,1,3,'2024-03-12 15:49:34','2024-03-12 15:49:34',NULL),
	 (95,'0-) Compromiso Ciudadano','Agradecemos tu compromiso ciudadano.',1,1,3,'2024-05-08 14:25:16','2024-05-08 14:25:16',NULL),
	 (96,'Puntualidad y Asistencia','Llegar, realizar y/o completar sus tareas, actividades o encuentros en el momento acordado, sin retrasos ni demoras.',1,1,3,'2024-05-08 14:26:11','2024-05-08 14:26:11',NULL),
	 (97,'1. Hambre','Ir por más y mejores escenarios',1,1,3,'2024-06-13 17:53:24','2024-06-18 07:56:23',NULL),
	 (98,'2. Habilidad','Ser competente y ser buena persona.',1,1,3,'2024-06-13 17:54:05','2024-06-18 07:52:17',NULL),
	 (99,'3. Humildad','Siempre en modo aprendiz.',1,1,3,'2024-06-13 17:54:48','2024-06-18 07:59:11',NULL),
	 (100,'4. Hermandad','Comparte el escenario con los demás.',1,1,3,'2024-06-13 17:55:30','2024-06-18 07:44:15',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (101,'TRIVIA RESTAURANTES','¡Muchas felicidades por tu conocimiento de la industria restaurantera!',1,1,1,'2024-06-25 14:24:05','2024-06-25 14:24:05',NULL),
	 (102,'Compañerismo','Para que te conviertas en un eslabón fuerte en nuestra cadena de éxitos.',1,1,3,'2024-08-16 11:17:47','2024-08-16 11:17:47',NULL),
	 (103,'Honestidad','Para que actúes con sinceridad y mostrar respeto hacia los demás y hacia ti mismo.',1,1,3,'2024-08-16 11:19:12','2024-08-16 11:19:12',NULL),
	 (104,'Humildad','Para aprender de todos aquellos que tienen algo nuevo y bueno que enseñarte y reconocer nuestros errores.',1,1,3,'2024-08-16 11:21:20','2024-08-16 11:21:20',NULL),
	 (105,'Justicia','Cuando se te presente la oportunidad de ayudar a resolver un problema.',1,1,3,'2024-08-16 11:26:14','2024-08-16 11:26:14',NULL),
	 (106,'Profesionalismo','En el desempeño de todas tus actividades.',1,1,3,'2024-08-16 11:28:58','2024-08-16 11:28:58',NULL),
	 (107,'Respeto','Para ti, para tus compañeros, tus subordinados, a las jerarquías, nuestros clientes y proveedores.',1,1,3,'2024-08-16 11:30:08','2024-08-16 11:30:08',NULL),
	 (108,'INNOVACIÓN Y CALIDAD','La innovación implica no solo creatividad, sino también la implementación de soluciones que mejoren la eficiencia y la efectividad. La calidad se centra en proporcionar productos y servicios que cumplan o superen las expectativas de los clientes.',1,1,3,'2024-10-10 11:14:30','2024-10-15 07:47:58',NULL),
	 (109,'RECONOCIMIENTO AL MÉRITO','Reconocer el mérito no solo implica recompensar el desempeño excepcional, sino también fomentar un ambiente donde se aprecie el esfuerzo y la dedicación de todos.',1,1,3,'2024-10-10 11:16:03','2024-10-15 07:47:33',NULL),
	 (110,'PASIÓN Y COMPROMISO','La pasión motiva a los empleados a dar lo mejor de sí, a innovar y a superar obstáculos. Un equipo comprometido trabaja no solo por cumplir con las tareas, sino por contribuir al éxito colectivo.',1,1,3,'2024-10-10 11:17:39','2024-10-15 07:47:16',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (111,'RESPETO Y CONFIANZA','El respeto fomenta un ambiente inclusivo y positivo donde cada persona se siente valorada, independientemente de su rol, antecedentes o ideas. Los colaboradores pueden contar unos con otros y sentirse en un entorno de confianza mutua, lo que crea un clima de seguridad, apertura para compartir ideas y cumplir expectativas.',1,1,3,'2024-10-10 11:18:26','2024-10-15 07:46:53',NULL),
	 (112,'TRABAJO EN EQUIPO','Promueve la idea de que el éxito se logra mejor cuando las personas trabajan juntas, compartiendo habilidades, conocimientos y recursos.',1,1,3,'2024-10-10 11:19:13','2024-10-15 07:46:41',NULL),
	 (113,'HONESTIDAD E INTEGRIDAD','La honestidad promueve un ambiente donde la comunicación abierta es valorada, y donde los empleados y clientes pueden confiar en que la información proporcionada es veraz. La integridad va un paso más allá de la honestidad; implica actuar de acuerdo con principios éticos y morales, incluso cuando nadie está mirando.',1,1,3,'2024-10-10 11:44:10','2024-10-15 07:46:17',NULL),
	 (114,'Diligencia','Persona responsable, responsiva y altamente proactiva',1,1,3,'2025-01-21 12:19:17','2025-01-21 12:19:17',NULL),
	 (115,'Obediencia','Persona que sigue instrucciones responsablemente. "La obediencia trae bendición y seguir las reglas trae éxito."',1,1,3,'2025-01-21 12:20:00','2025-01-21 12:20:00',NULL),
	 (116,'Libertad de elección','Poder decidir lo mejor conforme a tus procesos y procedimientos.',1,1,3,'2025-01-21 12:24:44','2025-01-21 12:24:44',NULL),
	 (117,'Nobleza','Humildad en el comportamiento, reconociendo cuando no se hacer algo, no puedo hacer algo o me equivoqué haciendo algo..',1,1,3,'2025-01-21 12:24:49','2025-01-21 12:24:49',NULL),
	 (118,'Innovación','Capacitación y mejora, "El que no crece, perece."',1,1,3,'2025-01-21 12:25:31','2025-01-21 12:25:31',NULL),
	 (119,'Out reach','Llevar fuera de la clínica nuestras pláticas, alcanzar a las masas fuera de la clínica, dando una plática de forma externa al menos 1 vez al mes.',1,1,3,'2025-01-21 12:25:59','2025-01-21 12:25:59',NULL),
	 (120,'Fortaleza','Utilizar lo que tenemos como dones y talentos, donde somos mejores.',1,1,3,'2025-01-21 12:26:08','2025-01-21 12:26:08',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (121,'Responsabilidad','Hacer lo que nos toca hacer, respondiendo si lo hacemos o no.',1,1,3,'2025-01-21 12:27:23','2025-01-21 12:27:23',NULL),
	 (122,'Servicio al Cliente','Atender necesidades del usuario de forma profesional, objetiva y amable',1,1,3,'2025-01-28 15:55:57','2025-01-28 15:55:57',NULL),
	 (123,'Honestidad','Rectitud moral, integridad y transparencia.',1,1,3,'2025-01-28 15:57:28','2025-01-28 15:57:28',NULL),
	 (124,'Trabajo en equipo','Coordinar e integrar esfuerzos entre todos sus integrantes ya que se necesita para lograr resultado positivo',1,1,3,'2025-01-28 15:58:10','2025-01-28 15:58:10',NULL),
	 (125,'Disciplina','Esmero, dedicación, puntualidad y orden en nuestro trabajo diario para lograr el éxito del programa',1,1,3,'2025-01-28 15:58:54','2025-01-28 15:58:54',NULL),
	 (126,'Lealtad','Fidelidad, compromiso, sentido de pertenencia y defensa de intereses.',1,1,3,'2025-01-28 15:59:00','2025-01-28 15:59:00',NULL),
	 (127,'Respeto a los demás','Cordialidad, armonía, aceptación e inclusión de cada uno de los integrantes en el ámbito laboral. Si deseo que me respeten debo respetar.',1,1,3,'2025-01-28 15:59:52','2025-01-28 15:59:52',NULL),
	 (128,'PROFESIONALISMO','Es la capacidad de desarrollar tu trabajo con compromiso, responsabilidad y eficiencia; siempre apegándonos a las normas establecidas por Caska y sus asociados de negocios.',1,1,3,'2025-01-29 17:07:17','2025-01-29 17:07:17',NULL),
	 (129,'RESPETO','La consideración y valoración especial o positiva ante alguien o algo, al que le reconocemos su valor o cualidades.',1,1,3,'2025-01-29 17:08:04','2025-01-29 17:08:04',NULL),
	 (130,'COMPROMISO','Como colaboradores asumimos un acuerdo con uno mismo, ante otras personas, la corporación y nuestros clientes, basado en nuestra política de calidad para ofrecer satisfacción en los servicios que ofrecemos.',1,1,3,'2025-01-29 17:08:43','2025-01-29 17:08:43',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (131,'COMUNICACIÓN','Principio esencial para brindar seguridad, que nos permite expresar ideas y necesidades, así como comprender a los demás. Esto nos permite resolver conflictos, un ambiente laboral saludable y lograr objetivos en común.',1,1,3,'2025-01-29 17:09:24','2025-01-29 17:09:24',NULL),
	 (132,'CALIDAD','Es lo que distingue a nuestros productos o servicios para satisfacer las necesidades de los clientes y consumidores finales. manteniendo con ellos una relación de calidad basada en un principio de "relaciones de mutuo beneficio", para asegurar la calidad del bien adquirido.',1,1,3,'2025-01-29 17:09:48','2025-01-29 17:09:48',NULL),
	 (133,'LIDERAZGO','Desarrollar habilidades individuales que influyan en otras personas o equipo de trabajo con la finalidad de aportar entusiasmo para el logro de metas y objetivos.',1,1,3,'2025-01-29 17:10:08','2025-01-29 17:10:08',NULL),
	 (134,'ETICA','Caska se apoya en una ética empresarial basada en los valores compartidos con nuestros colaboradores, partes interesadas y clientes.',1,1,3,'2025-01-29 17:12:27','2025-01-29 17:12:27',NULL),
	 (135,'HONESTIDAD','Actuar con rectitud y honradez en todo momento y/o circunstancia, con clientes, proveedores y con los mismos colaboradores y compañeros de trabajo.',1,1,3,'2025-01-29 17:16:28','2025-01-29 17:16:28',NULL),
	 (136,'INVITADO','Ponemos al INVITADO en el centro de todo lo que hacemos, ofreciendo un servicio SORPRENDENTE.',1,1,3,'2025-02-03 22:31:48','2025-02-03 22:31:48',NULL),
	 (137,'SOMOS TRADICIÓN MEXICANA','HONRAMOS NUESTRAS RAÍCES Y COMPARTIMOS LA AUTENTICIDAD DE LA COCINA MEXICANA.',1,1,3,'2025-02-03 22:34:03','2025-02-03 22:34:03',NULL),
	 (138,'LO HACEMOS POR EL INVITADO','Ponemos al INVITADO en el centro de todo lo que hacemos, ofreciendo un servicio SORPRENDENTE',1,1,3,'2025-02-03 22:35:12','2025-02-03 22:35:12',NULL),
	 (139,'RENTABILIDAD','impulsan la rentabilidad de nuestra organización a través de su dedicación, innovación y compromiso. Su contribución es fundamental para nuestro éxito.',1,1,3,'2025-02-03 22:39:41','2025-02-03 22:39:41',NULL),
	 (140,'SOMOS DIFERENCIALES','Esta insignia se otorga a aquellos colaboradores que piensan fuera de la caja, generan ideas innovadoras y contribuyen a crear una cultura de excelencia y diferenciación en nuestra organización',1,1,3,'2025-02-03 22:41:57','2025-02-03 22:41:57',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (141,'SOMOS EQUIPO','TRABAJAMOS EN EQUIPO Y CONSTRUIMOS RELACIONES GENUINAS CON NUESTROS INVITADOS, COMO UNA GRAN EQUIPO',1,1,3,'2025-02-03 22:42:35','2025-02-03 22:42:35',NULL),
	 (142,'SOMOS INNOVADORES','FUSIONAMOS CREATIVIDAD Y TRADICIÓN PARA SORPRENDER Y DELEITAR A NUESTROS INVITADOS.',1,1,3,'2025-02-03 22:43:36','2025-02-03 22:43:36',NULL),
	 (143,'TALENTO','NOS ESFORZAMOS POR BRINDAR UNA CALIDAD Y SERVICIO IMPECABLES EN CADA DETALLE',1,1,3,'2025-02-03 22:44:59','2025-02-03 22:44:59',NULL),
	 (144,'TALENTO DEL MES','Esta insignia se otorga a aquellos colaboradores que han demostrado un desempeño sobresaliente en su área de trabajo, superando expectativas y contribuyendo al crecimiento y éxito de nuestra organización',1,1,3,'2025-02-03 22:46:42','2025-02-03 22:46:42',NULL),
	 (145,'Honestidad','Hablar y actuar con sinceridad, es más que no mentir o engañar. Implica mostrar respeto hacia los demás, tener integridad y consciencia de sí mismo.',1,1,3,'2025-02-27 14:24:40','2025-02-27 14:24:40',NULL),
	 (146,'Respondabilidad','Es la capacidad de cumplir con las obligaciones, cuidar el hacer o decidir algo, y hacerse cargo de las consecuencias de los actos.',1,1,3,'2025-02-27 14:26:19','2025-02-27 14:26:19',NULL),
	 (147,'Trabajo en equipo','Es la colaboración de un grupo de personas para lograr un objetivo en común, en el que cada integrante aporta sus conocimientos y habilidades.',1,1,3,'2025-02-27 14:27:56','2025-02-27 14:27:56',NULL),
	 (148,'Confianza','Emoción que se caracteriza por creer sin dudas ni inquietud y transmitarla a nuevos huéspedes.',0,0,1,'2025-02-27 14:30:15','2025-02-27 14:30:15',NULL),
	 (149,'Capacitación','Tener el valor y ganas de aprender, de seguir creciendo día a día.',1,1,3,'2025-02-27 14:32:46','2025-02-27 14:32:46',NULL),
	 (150,'Satisfacción del huésped','Vocación de servicio, prestación humana que satisface una necesidad.',1,1,3,'2025-02-27 14:34:53','2025-02-27 14:34:53',NULL);
INSERT INTO reconocimientos (id,nombre,descripcion,es_enviable,es_exclusivo,menciones_necesarias,created_at,updated_at,deleted_at) VALUES
	 (151,'Atracción de Clientes','Se siente orgulloso de la marca, es aliado principal para referir clientes buscando usuarios felices.',1,1,3,'2025-03-25 16:05:38','2025-03-25 16:05:38',NULL),
	 (152,'Trabajo Impecable','Lleva a cabo su trabajo de forma efectiva, cumpliendo con tiempos esperados, asumiendo sus responsabilidades de forma eficiente con sus clientes internos y/o externos, enfocado en resultados.',1,1,3,'2025-03-25 16:09:22','2025-03-25 16:09:22',NULL),
	 (153,'Liderazgo','Muestra una actitud pro activa dentro de su rol, es visible su esfuerzo por encontrar el "como si", inspira un nivel de alto desempeño',1,1,3,'2025-03-25 16:10:22','2025-03-25 16:10:22',NULL),
	 (154,'Contribución a los demás','Se involucra y aporta, muestra voluntad para apoyar a los demás, rompe barreras de comunicación para que los procesos fluyan o nos podamos anticipar a problema.',1,1,3,'2025-03-25 16:11:34','2025-03-25 16:11:34',NULL),
	 (155,'1-) PASIÓN','Lo que hacemos, lo hacemos bien y si podemos lo mejoramos.',1,1,3,'2025-05-02 20:42:23','2025-05-03 09:29:09',NULL),
	 (156,'2-) INTEGRIDAD','Ser auténticos, confiables y empáticos.',1,1,3,'2025-05-02 20:44:39','2025-05-03 09:29:24',NULL),
	 (157,'3-) LIDERAZGO','El coraje de forjar un futuro mejor basado en la innovación.',1,1,3,'2025-05-02 20:46:33','2025-05-03 09:29:39',NULL),
	 (158,'4-) LEALTAD','Comprometidos con el corazón y la razón.',1,1,3,'2025-05-02 20:48:06','2025-05-03 09:29:56',NULL),
	 (159,'5+ años con Dolorfin','En DOLORFIN, valoramos profundamente la lealtad, el compromiso y la pasión que cada colaborador aporta día con día. Este reconocimiento es una muestra de nuestro más sincero agradecimiento por tus 5 años o más de entrega constante, profesionalismo y por ser parte esencial de nuestra historia y crecimiento desde el inicio.',1,1,1,'2025-05-29 13:14:53','2025-05-29 13:14:53',NULL),
	 (160,'RESPETO','Tratar a todos como te gustaría ser tratado, con humildad, justicia e integridad.',1,1,3,'2025-05-30 10:31:33','2025-05-30 10:31:33',NULL);
