	 (162,'PASIÓN POR EL SERVICIO','Amor por lo que hacemos con actitud proactiva superando consistentemente las expectativas de nuestros compañeros de trabajo, clientes, proveedores y comunidad.',1,1,3,'2025-05-30 10:34:08','2025-05-30 10:34:08',NULL),
	 (163,'LEALTAD','Estar orgulloso y comprometido con tu trabajo, buscando el bienestar común.',1,1,3,'2025-05-30 11:03:40','2025-05-30 11:03:40',NULL),
	 (164,'TRABAJO EN EQUIPO','Colaboración entusiasta para un fin común.',1,1,3,'2025-05-30 11:04:36','2025-05-30 11:04:36',NULL),
	 (165,'TRABAJO BIEN HECHO','Hacer tu trabajo bien y a la primera enfocado al logro de resultados.',1,1,3,'2025-05-30 11:05:51','2025-05-30 11:05:51',NULL),
	 (166,'DIVERSIÓN','Vive con alegría y disfruta tu trabajo.',1,1,3,'2025-05-30 11:06:35','2025-05-30 11:06:35',NULL),
	 (167,'LIDERAZGO','Inspira, enseña y guía con tu ejemplo.',1,1,3,'2025-05-30 11:07:18','2025-05-30 11:07:18',NULL),
	 (168,'HONESTIDAD','Hacemos lo correcto, aunque nadie nos esté mirando',1,1,3,'2025-06-23 15:43:09','2025-06-23 15:43:27',NULL),
	 (169,'CALIDAD','La percepción de nuestros clientes es la única verdad, somos capaces de cubrir sus necesidades de una forma que ni ellos imaginan.',1,1,3,'2025-06-23 15:45:14','2025-06-23 15:45:14',NULL),
