	 (185,'INCLUSIÓN','Respetar y garantizar el respeto e igualdad de oportunidad y equidad.',1,1,3,'2025-07-17 10:45:10','2025-07-17 10:45:10',NULL),
	 (186,'SERVICIO','Garantizar y brindar soluciones efectivas a nuestros clientes y compañeros de forma efectiva, manteniendo el respeto, calidez y profesionalismo.',1,1,3,'2025-07-17 10:46:12','2025-07-17 10:46:12',NULL),
	 (187,'ATENCIÓN','Brindar al cliente la mejor atención identificando las necesidades, proporcionando la orientación personalizada de nuestro calzado, aportando al cliente: empatía, atención y servicio.',1,1,3,'2025-07-17 16:43:17','2025-07-17 16:43:17',NULL),
	 (188,'INTEGRIDAD','Mantener el respeto y apego del cumplimiento de todos nuestros procesos, garantizando la calidad y servicio Que realizamos.',1,1,3,'2025-07-17 16:44:22','2025-07-17 16:44:22',NULL),
	 (189,'RESPONSABILIDAD','Cumplir con las actividades de operación para tener en todas nuestras sucursales una gamma amplia de calzado y brindar al cliente un servicio de calidad.',1,1,3,'2025-07-17 16:45:26','2025-07-17 16:45:26',NULL),
	 (190,'COMPROMISO','Tener la responsabilidad de garantizar, brindar el apoyo, comunicación y características en cada producto: garantía, calidad, diseño. Generando la satisfacción del cliente.',1,1,3,'2025-07-17 16:46:33','2025-07-17 16:46:33',NULL);
