	 (192,'TRABAJO EN EQUIPO','Colaborar entre todas las áreas y con los clientes para lograr soluciones integrales en proyectos inmobiliarios y de mobiliario, sumando talentos para alcanzar mejores resultados.',1,1,3,'2025-08-20 20:58:35','2025-08-20 20:58:35',NULL),
	 (193,'RESPETO','Valorar a cada persona, cliente y colaborador, escuchando y atendiendo sus necesidades con empatía y profesionalismo, fomentando relaciones duraderas y justas.',1,1,3,'2025-08-20 20:59:21','2025-08-20 20:59:21',NULL),
